export function getItemById(id: string): LikedItem | undefined {
  return items.find((item) => item.id === id);
}

export function getItemsByCluster(cluster: string): LikedItem[] {
  return items.filter((item) => item.cluster === cluster);
}

export function getItemsBySource(source: string): LikedItem[] {
  return items.filter((item) => item.source === source);
}
